// ─── CHARACTERS DATA ───
const CHARACTERS = [
  {
    id: 'rei',
    name: 'REI',
    img: 'data:image/jpeg;base64,',
    color: '#00cfff',
    dark: '#007fa0',
    stats: { velocita: 75, salto: 90, potenza: 60 },
    desc: 'Tecnica e precisa 🎯',
    trait: 'Alto salto, colpi accurati',
    jumpBonus: 1.12,
    speedBonus: 1.0,
    hitBonus: 0.95
  },
  {
    id: 'sissy',
    name: 'SISSY',
    img: 'data:image/jpeg;base64,',
    color: '#ff6bbd',
    dark: '#c0007f',
    stats: { velocita: 90, salto: 70, potenza: 85 },
    desc: 'Veloce e potente 🌸',
    trait: 'Smash devastante, sprint rapido',
    jumpBonus: 0.95,
    speedBonus: 1.18,
    hitBonus: 1.15
  }
];

let selectedCharId = null;

function buildCharCards() {
  const row = document.getElementById('charCardsRow');
  row.innerHTML = '';
  CHARACTERS.forEach(ch => {
    const card = document.createElement('div');
    card.className = 'char-card';
    card.id = 'card-' + ch.id;
    card.onclick = () => selectChar(ch.id);
    card.innerHTML = `
      <div class="char-card-img-wrap">
        <img src="${ch.img}" alt="${ch.name}">
        <div class="char-selected-badge">✓</div>
      </div>
      <div class="char-name">${ch.name}</div>
      <div class="char-stats">
        ${Object.entries(ch.stats).map(([k,v]) => `
          <div class="char-stat-row">
            <span style="width:56px">${k}</span>
            <div class="char-stat-bar-bg">
              <div class="char-stat-bar-fill" style="width:${v}%"></div>
            </div>
          </div>
        `).join('')}
      </div>
      <div class="char-desc">${ch.desc}<br><span style="color:rgba(255,255,255,.3);font-size:.65rem">${ch.trait}</span></div>
    `;
    row.appendChild(card);
  });
}

function selectChar(id) {
  selectedCharId = id;
  document.querySelectorAll('.char-card').forEach(c => c.classList.remove('selected'));
  document.getElementById('card-' + id).classList.add('selected');
  const ch = CHARACTERS.find(c => c.id === id);
  document.getElementById('charSelectHint').textContent = ch.name + ' selezionato! Pronto a giocare?';
  document.getElementById('charSelectHint').style.color = ch.color;
  const btn = document.getElementById('btnStartGame');
  btn.classList.add('ready');
}

// ─── BG PARTICLES ───
const bgC=document.getElementById('bgCanvas'),bgX=bgC.getContext('2d');
let parts=[];
function initBg(){
  bgC.width=innerWidth; bgC.height=innerHeight;
  parts=Array.from({length:55},()=>({
    x:Math.random()*bgC.width,y:Math.random()*bgC.height,
    r:Math.random()*1.4+.3,vx:(Math.random()-.5)*.25,vy:(Math.random()-.5)*.25,
    a:Math.random()*.35+.05
  }));
}
function animBg(){
  bgX.clearRect(0,0,bgC.width,bgC.height);
  parts.forEach(p=>{
    p.x+=p.vx; p.y+=p.vy;
    if(p.x<0)p.x=bgC.width; if(p.x>bgC.width)p.x=0;
    if(p.y<0)p.y=bgC.height; if(p.y>bgC.height)p.y=0;
    bgX.beginPath(); bgX.arc(p.x,p.y,p.r,0,Math.PI*2);
    bgX.fillStyle=`rgba(245,166,35,${p.a})`; bgX.fill();
  });
  requestAnimationFrame(animBg);
}
window.addEventListener('resize',initBg);
initBg(); animBg();
buildCharCards();

// ─── SETTINGS ───
const DIFF_LABELS=['FACILE','MEDIA','DIFFICILE','ESTREMA'];
const SPD_LABELS=['LENTA','NORMALE','VELOCE'];
const S={winScore:7,difficulty:1,ballSpeed:1};
function changeSetting(k,d){
  if(k==='winScore'){S.winScore=Math.max(3,Math.min(15,S.winScore+d));document.getElementById('val-winScore').textContent=S.winScore;}
  else if(k==='difficulty'){S.difficulty=Math.max(0,Math.min(3,S.difficulty+d));document.getElementById('val-difficulty').textContent=DIFF_LABELS[S.difficulty];}
  else if(k==='ballSpeed'){S.ballSpeed=Math.max(0,Math.min(2,S.ballSpeed+d));document.getElementById('val-ballSpeed').textContent=SPD_LABELS[S.ballSpeed];}
}
function showScreen(id){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById(id).classList.add('active');}
function pauseToMenu(){gameRunning=false;document.getElementById('winOverlay').classList.remove('show');showScreen('menuScreen');}
function showFoulMessage(player){
  const msg=document.getElementById('foulMessage');
  msg.textContent='\u26a0\ufe0f '+player+' FALLO!';
  msg.style.opacity='1';
  setTimeout(()=>{msg.style.opacity='0';},1500);
}

// ─── GAME ───
const canvas=document.getElementById('gameCanvas'),ctx=canvas.getContext('2d');
let W,H,GY,NX,NH;

function resize(){
  const barH=44;
  W=Math.min(innerWidth,1400);
  H=Math.min(innerHeight-barH,750);
  canvas.width=W; canvas.height=H;
  GY=H-60; NX=W/2; NH=Math.round(H*.2);
}

const GRAV=0.50, PW=54,PH=68, BR=32;
const PSPEED=4.8, JFORCE=-15.5;
const SPDMUL=[.8,1.0,1.3];
const AI_CFG=[
  {spd:1.2,react:.01,err:120,jdelay:50},
  {spd:3.2,react:.08,err:45,jdelay:20},
  {spd:3.0,react:.05,err:60,jdelay:25},
  {spd:4.0,react:.08,err:30,jdelay:15}
];

let keys={},mouseX=-1,gameRunning=false;
let ball,player,ai,scoreP=0,scoreA=0,serving='player',aiJT=0,roundCount=0,roundStartTime=0;

// Char images
let imgPlayer = null, imgAI = null;

function loadCharImages() {
  const ch = CHARACTERS.find(c => c.id === selectedCharId) || CHARACTERS[0];
  // AI always uses the other character
  const aiCh = CHARACTERS.find(c => c.id !== selectedCharId) || CHARACTERS[1];
  imgPlayer = new Image(); imgPlayer.src = ch.img;
  imgAI = new Image(); imgAI.src = aiCh.img;
}

canvas.addEventListener('mousemove',e=>{const r=canvas.getBoundingClientRect();mouseX=e.clientX-r.left;});
canvas.addEventListener('mouseleave',()=>{mouseX=-1;});
window.addEventListener('keydown',e=>{
  keys[e.code]=true;
  if(['ArrowUp','ArrowDown','ArrowLeft','ArrowRight','Space'].includes(e.code))e.preventDefault();
  if(e.code==='Escape'&&gameRunning)pauseToMenu();
});
window.addEventListener('keyup',e=>{keys[e.code]=false;});

function mkBall(side){
  const m=SPDMUL[S.ballSpeed];
  const roundMul=Math.max(0.5,1.0-roundCount*0.08);
  return{x:side==='player'?W*.27:W*.73,y:0,
    vx:(side==='player'?0.3:-0.3)*m*roundMul,vy:0.08*m,r:BR,rot:0,lastHit:null,consecutiveHits:0};
}
function mkPlayer(){return{x:W*.18,y:GY,vx:0,vy:0,onGround:true,hitCD:0,sq:1};}
function mkAI()    {return{x:W*.82,y:GY,vx:0,vy:0,onGround:true,hitCD:0,sq:1,tx:W*.75};}

function resetAll(srv){
  ball=mkBall(srv); player=mkPlayer(); ai=mkAI(); aiJT=0;
  roundCount++;
  roundStartTime=Date.now();
}

function tickAI(){
  const cfg=AI_CFG[S.difficulty];
  let bx=ball.x,by=ball.y,bvx=ball.vx,bvy=ball.vy,pred=ai.x;
  for(let t=0;t<100;t++){
    bvy+=GRAV; bx+=bvx; by+=bvy;
    if(by+BR>=GY){pred=bx;break;}
    if(bx-BR<0){bx=BR;bvx=Math.abs(bvx);}
    if(bx+BR>W){bx=W-BR;bvx=-Math.abs(bvx);}
    if(Math.abs(bx-NX)<9&&by>GY-NH){bvx*=-.85;}
  }
  pred+=(Math.random()-.5)*cfg.err;
  pred=Math.max(NX+35,Math.min(W-PW-10,pred));
  ai.tx+=(pred-ai.tx)*cfg.react;
  const diff=ai.tx-(ai.x+PW/2);
  if(Math.abs(diff)>5) ai.vx=Math.sign(diff)*Math.min(Math.abs(diff)*.3,cfg.spd);
  else ai.vx*=.6;
  if(aiJT>0){aiJT--;return;}
  const dist=Math.hypot(ball.x-(ai.x+PW/2),ball.y-ai.y);
  if(dist<95&&ai.onGround&&ball.x>NX+15){
    ai.vy=JFORCE*.93; ai.onGround=false; aiJT=cfg.jdelay;
  }
}

function tickChar(c,isAI){
  c.vy+=GRAV; c.x+=c.vx; c.y+=c.vy;
  const minX=isAI?NX+9:0;
  const maxX=isAI?W-PW-4:NX-PW-9;
  c.x=Math.max(minX,Math.min(maxX,c.x));
  if(c.y>=GY){c.y=GY;c.vy=0;c.onGround=true;}
  c.sq+=((1)-c.sq)*.15;
}

function getPlayerChar() {
  return CHARACTERS.find(c => c.id === selectedCharId) || CHARACTERS[0];
}
function getAIChar() {
  return CHARACTERS.find(c => c.id !== selectedCharId) || CHARACTERS[1];
}

function tickInput(){
  const ch = getPlayerChar();
  const spd = PSPEED * ch.speedBonus;
  if(keys['ArrowLeft']||keys['KeyA'])player.vx=-spd;
  else if(keys['ArrowRight']||keys['KeyD'])player.vx=spd;
  else player.vx=0;
  const jf = JFORCE * ch.jumpBonus;
  if((keys['ArrowUp']||keys['Space']||keys['KeyW'])&&player.onGround){
    player.vy=jf; player.onGround=false;
  }
}

function overlap(bx,by,br,rx,ry,rw,rh){
  const cx=Math.max(rx,Math.min(rx+rw,bx));
  const cy=Math.max(ry-rh,Math.min(ry,by));
  return Math.hypot(bx-cx,by-cy)<br+4;
}
function tryHit(c,isAI){
  if(Date.now()<c.hitCD)return;
  if(!overlap(ball.x,ball.y,ball.r,c.x,c.y,PW,PH))return;
  const whoIsHitting=isAI?'ai':'player';
  if(ball.lastHit===whoIsHitting){
    ball.consecutiveHits++;
    if(ball.consecutiveHits>=4){showFoulMessage(whoIsHitting==='ai'?'AI':'TU');return;}
  }else{ball.consecutiveHits=1;ball.lastHit=whoIsHitting;}
  const cx=c.x+PW/2, cy=c.y;
  const impactX=ball.x-cx, impactY=ball.y-cy;
  const impactLen=Math.hypot(impactX,impactY);
  const normX=impactX/impactLen, normY=impactY/impactLen;
  const m=SPDMUL[S.ballSpeed];
  const ch = isAI ? getAIChar() : getPlayerChar();
  const baseSpd=(5.5+Math.random()*1.5)*m*ch.hitBonus;
  let velocityX=normX*baseSpd + c.vx*0.4;
  let verticalBoost=isAI?-3.2:-4.0;
  if(isAI && ball.y < GY - 120) verticalBoost = -2.4;
  let velocityY=normY*baseSpd + verticalBoost;
  const maxSpeed=7.0*m;
  const currentSpeed=Math.hypot(velocityX,velocityY);
  if(currentSpeed>maxSpeed){const scale=maxSpeed/currentSpeed;velocityX*=scale;velocityY*=scale;}
  if(isAI) velocityX=-Math.max(Math.abs(velocityX),2.4*m);
  else velocityX=Math.max(Math.abs(velocityX),2.4*m);
  ball.vx=velocityX; ball.vy=velocityY;
  c.hitCD=Date.now()+400; c.sq=.6;
}

function tickBall(){
  ball.vy+=GRAV*0.20;
  ball.x+=ball.vx; ball.y+=ball.vy;
  ball.rot+=ball.vx*.08;
  if(ball.x-ball.r<0){ball.x=ball.r;ball.vx=Math.abs(ball.vx)*.8;}
  if(ball.x+ball.r>W){ball.x=W-ball.r;ball.vx=-Math.abs(ball.vx)*.8;}
  const nt=GY-NH;
  if(ball.y>nt&&ball.y<GY&&Math.abs(ball.x-NX)<ball.r+6){
    if(ball.x<NX){ball.x=NX-(ball.r+7);ball.vx=-Math.abs(ball.vx)*.7;}
    else{ball.x=NX+(ball.r+7);ball.vx=Math.abs(ball.vx)*.7;}
  }
  if(ball.y+ball.r>=GY){
    const side=ball.x<NX?'player':'ai';
    if(side==='player'){scoreA++;serving='ai';}
    else{scoreP++;serving='player';}
    checkWin();
    if(gameRunning)resetAll(serving);
  }
}

function checkWin(){
  if(scoreP>=S.winScore||scoreA>=S.winScore){
    gameRunning=false;
    const won=scoreP>=S.winScore;
    const ch = getPlayerChar();
    const aiCh = getAIChar();
    document.getElementById('winEmoji').textContent=won?'🏆':'🤖';
    document.getElementById('winTitle').textContent=won?`${ch.name} VINCE!`:`${aiCh.name} VINCE!`;
    document.getElementById('winTitle').style.color=won?ch.color:aiCh.color;
    document.getElementById('winSub').textContent=`${scoreP} — ${scoreA}`;
    document.getElementById('winOverlay').classList.add('show');
  }
}

// ─── DRAW ───
function drawCourt(){
  const sky=ctx.createLinearGradient(0,0,0,GY);
  sky.addColorStop(0,'#0b1330'); sky.addColorStop(.6,'#112050'); sky.addColorStop(1,'#1a3060');
  ctx.fillStyle=sky; ctx.fillRect(0,0,W,GY);
  ctx.fillStyle='rgba(255,255,255,0.4)';
  for(let i=0;i<30;i++){
    const sx=((i*137.5)%W), sy=((i*97.3)%GY*.7);
    ctx.beginPath(); ctx.arc(sx,sy,i%3===0?.8:.4,0,Math.PI*2); ctx.fill();
  }
  const sand=ctx.createLinearGradient(0,GY,0,H);
  sand.addColorStop(0,'#d4a843'); sand.addColorStop(1,'#a8822a');
  ctx.fillStyle=sand; ctx.fillRect(0,GY,W,H-GY);
  ctx.strokeStyle='rgba(180,140,30,.2)'; ctx.lineWidth=1;
  for(let y=GY+7;y<H;y+=7){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
  ctx.strokeStyle='rgba(255,255,255,.18)'; ctx.lineWidth=2;
  [28,W-28].forEach(x=>{ctx.beginPath();ctx.moveTo(x,GY-2);ctx.lineTo(x,H);ctx.stroke();});
  ctx.strokeStyle='rgba(255,255,255,.08)'; ctx.lineWidth=1.5;
  ctx.setLineDash([6,6]);
  ctx.beginPath();ctx.moveTo(0,GY);ctx.lineTo(W,GY);ctx.stroke();
  ctx.setLineDash([]);
  const nt=GY-NH;
  ctx.fillStyle='#c8c8c8'; ctx.fillRect(NX-5,nt-12,10,NH+12);
  ctx.strokeStyle='rgba(255,255,255,.3)'; ctx.lineWidth=1;
  for(let y=nt;y<GY;y+=13){ctx.beginPath();ctx.moveTo(NX-4,y);ctx.lineTo(NX+4,y);ctx.stroke();}
  ctx.fillStyle='#eee'; ctx.fillRect(NX-4,nt-12,8,7);
  for(let i=0;i<7;i++){
    ctx.fillStyle=i%2===0?'#ff2020':'#fff';
    ctx.fillRect(NX-3,nt-12-i*8,6,8);
  }
}

function drawBall(){
  ctx.save();
  ctx.translate(ball.x,ball.y); ctx.rotate(ball.rot+Math.sin(Date.now()*0.003)*0.2);
  ctx.save(); ctx.translate(4,6);
  ctx.beginPath(); ctx.arc(0,0,ball.r,0,Math.PI*2);
  ctx.fillStyle='rgba(0,0,0,.28)'; ctx.fill(); ctx.restore();
  ctx.beginPath(); ctx.arc(0,0,ball.r,0,Math.PI*2);
  ctx.fillStyle='#ffffff'; ctx.fill();
  const panelColors=['#00a0e9','#ffd700','#ff6b35'];
  for(let i=0;i<6;i++){
    ctx.save(); ctx.rotate((Math.PI/3)*i);
    ctx.beginPath(); ctx.moveTo(0,0); ctx.arc(0,0,ball.r,0,Math.PI/3); ctx.closePath();
    ctx.fillStyle=panelColors[i%3]; ctx.fill(); ctx.restore();
  }
  ctx.strokeStyle='rgba(0,0,0,.15)'; ctx.lineWidth=1.5;
  for(let i=0;i<6;i++){
    ctx.save(); ctx.rotate((Math.PI/3)*i);
    ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(ball.r*Math.cos(Math.PI/6),ball.r*Math.sin(Math.PI/6)); ctx.stroke(); ctx.restore();
  }
  ctx.strokeStyle='rgba(0,0,0,.2)'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.arc(0,0,ball.r,0,Math.PI*2); ctx.stroke();
  ctx.restore();
}

function drawCharSprite(c, isAI) {
  const cx = c.x + PW/2;
  const img = isAI ? imgAI : imgPlayer;
  const ch = isAI ? getAIChar() : getPlayerChar();
  // Shadow
  ctx.save(); ctx.translate(cx, GY); ctx.scale(1,.28);
  ctx.fillStyle='rgba(0,0,0,.25)'; ctx.beginPath();
  ctx.ellipse(0,0,PW*.5,9,0,0,Math.PI*2); ctx.fill(); ctx.restore();

  if(img && img.complete && img.naturalWidth > 0){
    ctx.save();
    ctx.shadowColor = ch.color + 'bb'; ctx.shadowBlur = 22;
    ctx.translate(cx, c.y - PH/2);
    ctx.scale(c.sq < 1 ? 1.1 : 1, c.sq);
    // Flip AI horizontally so it faces left
    if(isAI){ ctx.scale(-1,1); }
    ctx.drawImage(img, -PW/2, -PH/2, PW, PH);
    ctx.restore();

    // Name tag above character
    ctx.save();
    ctx.font = 'bold 10px "Black Ops One",monospace';
    ctx.textAlign = 'center';
    ctx.fillStyle = ch.color;
    ctx.shadowColor = ch.color; ctx.shadowBlur = 8;
    ctx.fillText(ch.name, cx, c.y - PH - 6);
    ctx.restore();
    return;
  }

  // Fallback drawn character
  const col = ch.color, drk = ch.dark;
  ctx.save(); ctx.translate(cx, c.y);
  ctx.scale(c.sq < 1 ? 1+(1-c.sq)*.5 : 1, c.sq);
  ctx.fillStyle = drk;
  const lv = c.onGround ? 0 : Math.sin(Date.now()*.018)*7;
  ctx.fillRect(-PW/2+7,-24+lv,14,24); ctx.fillRect(PW/2-21,-24-lv,14,24);
  ctx.shadowColor=col; ctx.shadowBlur=18; ctx.fillStyle=col;
  ctx.beginPath(); ctx.roundRect(-PW/2+4,-PH+10,PW-8,PH-30,8); ctx.fill();
  ctx.beginPath(); ctx.arc(0,-PH+9,19,0,Math.PI*2); ctx.fill();
  ctx.shadowBlur=0;
  ctx.fillStyle='#fff';
  ctx.beginPath(); ctx.arc(-6,-PH+7,5,0,Math.PI*2); ctx.arc(6,-PH+7,5,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#111';
  ctx.beginPath(); ctx.arc(-5,-PH+8,2.5,0,Math.PI*2); ctx.arc(7,-PH+8,2.5,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle=col; ctx.lineWidth=7; ctx.lineCap='round';
  const aa=c.onGround?.3:.9;
  ctx.beginPath(); ctx.moveTo(-PW/2+4,-PH+30); ctx.lineTo(-PW/2+4-14*Math.cos(aa),-PH+30+12*Math.sin(aa)); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(PW/2-4,-PH+30); ctx.lineTo(PW/2-4+14*Math.cos(aa),-PH+30+12*Math.sin(aa)); ctx.stroke();
  ctx.restore();
}

function drawHUD(){
  const ch = getPlayerChar();
  const aiCh = getAIChar();
  const cooldownElapsed=Date.now()-roundStartTime;
  const inCooldown=cooldownElapsed<2000;
  const bw=240,bh=54,bx=W/2-120,by=10;
  ctx.fillStyle='rgba(0,0,0,.58)'; ctx.beginPath(); ctx.roundRect(bx,by,bw,bh,12); ctx.fill();
  ctx.strokeStyle='rgba(255,255,255,.06)'; ctx.lineWidth=1; ctx.beginPath(); ctx.roundRect(bx,by,bw,bh,12); ctx.stroke();
  ctx.textAlign='center';
  ctx.font='bold 34px "Black Ops One",monospace';
  ctx.fillStyle=ch.color; ctx.shadowColor=ch.color+'88'; ctx.shadowBlur=14;
  ctx.fillText(scoreP,W/2-60,by+40);
  ctx.fillStyle=aiCh.color; ctx.shadowColor=aiCh.color+'88';
  ctx.fillText(scoreA,W/2+60,by+40);
  ctx.shadowBlur=0;
  ctx.fillStyle='rgba(255,255,255,.25)'; ctx.font='16px "Exo 2",sans-serif';
  ctx.fillText('—',W/2,by+38);
  ctx.font='bold 10px "Exo 2",sans-serif';
  ctx.fillStyle=ch.color+'bb'; ctx.textAlign='left'; ctx.fillText(ch.name,bx+12,by+17);
  ctx.fillStyle=aiCh.color+'bb'; ctx.textAlign='right'; ctx.fillText(aiCh.name+' AI',bx+bw-12,by+17);
  ctx.fillStyle='rgba(255,255,255,.2)'; ctx.font='9px "Exo 2",sans-serif'; ctx.textAlign='center';
  ctx.fillText('primo a '+S.winScore,W/2,by+bh+12);
  if(inCooldown){
    const secondsLeft=Math.ceil((2000-cooldownElapsed)/1000);
    ctx.font='bold 48px "Black Ops One",monospace';
    ctx.fillStyle='rgba(255,100,100,0.9)'; ctx.shadowColor='rgba(255,100,100,.8)'; ctx.shadowBlur=20;
    ctx.textAlign='center'; ctx.fillText(secondsLeft,W/2,H/2+20); ctx.shadowBlur=0;
  }
  ctx.font='bold 11px "Exo 2",sans-serif';
  ctx.fillStyle=ch.color+'66'; ctx.textAlign='left'; ctx.fillText('◀ '+ch.name,14,H-10);
  ctx.fillStyle=aiCh.color+'66'; ctx.textAlign='right'; ctx.fillText(aiCh.name+' ▶',W-14,H-10);
}

function loop(){
  if(!gameRunning)return;
  ctx.clearRect(0,0,W,H);
  const cooldownElapsed=Date.now()-roundStartTime;
  const inCooldown=cooldownElapsed<2000;
  if(!inCooldown){
    tickInput(); tickAI();
    tickChar(player,false); tickChar(ai,true);
    tickBall();
    tryHit(player,false); tryHit(ai,true);
  }
  drawCourt(); drawCharSprite(player,false); drawCharSprite(ai,true); drawBall(); drawHUD();
  requestAnimationFrame(loop);
}

function startGame(){
  if(!selectedCharId) return;
  loadCharImages();
  resize(); scoreP=0; scoreA=0; serving='player'; roundCount=0;
  resetAll(serving);
  document.getElementById('winOverlay').classList.remove('show');
  showScreen('gameScreen');
  gameRunning=true; loop();
}
function restartGame(){
  document.getElementById('winOverlay').classList.remove('show');
  scoreP=0; scoreA=0; serving='player'; roundCount=0;
  resetAll(serving);
  gameRunning=true; loop();
}
window.addEventListener('resize',()=>{
  if(document.getElementById('gameScreen').classList.contains('active')){
    resize(); resetAll(serving);
  }
});